blocks.body:
{
  "level": "B1",
  "intro": "W tym temacie nauczysz się używać <strong>strony biernej z modalami</strong>, np. <em>can, could, may, might, must, should, will, would</em>.",
  "rules": [
    {
      "label": "Wzór",
      "color": "emerald",
      "text": "<strong>subject + modal + be + V3</strong>:",
      "example": "This task must be done today."
    },
    {
      "label": "Przeczenie",
      "color": "rose",
      "text": "<strong>subject + modal + not + be + V3</strong>:",
      "example": "This task cannot be done today."
    },
    {
      "label": "Pytanie",
      "color": "blue",
      "text": "<strong>Modal + subject + be + V3?</strong>:",
      "example": "Can this task be done today?"
    }
  ]
}

{
    "title": "1. Czasowniki modalne w stronie biernej",
    "intro": "Wzór: <strong>modalny + be + V3</strong>:",
    "items": [
        {
            "label": "Móc",
            "title": "można to zrobić",
            "subtitle": "Można to naprawić. - Można to naprawić."
        },
        {
            "label": "mógł",
            "title": "można to zrobić",
            "subtitle": "Można to poprawić. — Można to poprawić."
        },
        {
            "label": "móc",
            "title": "może być zrobione",
            "subtitle": "Może zostać przełożone. - Można to przełożyć."
        },
        {
            "label": "móc",
            "title": "może być zrobione",
            "subtitle": "Może zostać anulowane. - Można to anulować."
        },
        {
            "label": "musieć",
            "title": "trzeba to zrobić",
            "subtitle": "To musi być skończone. - To musi zostać dokończone."
        },
        {
            "label": "powinien",
            "title": "powinno zostać zrobione",
            "subtitle": "Należy to sprawdzić. – Warto sprawdzić."
        },
        {
            "label": "będzie",
            "title": "zostanie zrobione",
            "subtitle": "Zostanie ukończone. - To zostanie ukończone."
        },
        {
            "label": "zrobiłbym",
            "title": "byłoby zrobione",
            "subtitle": "Byłoby to docenione. - To byłoby mile widziane."
        }
    ]
}

{
    "title": "2. Znaczenie czasowników modalnych w stronie biernej",
    "sections": [
        {
            "label": "może / mógłby",
            "color": "emerald",
            "description": "<strong>Możliwość</strong> lub <strong>zdolność</strong>:",
            "examples": [
                {
                    "en": "The problem can be solved easily.",
                    "ua": "Problem można łatwo rozwiązać."
                },
                {
                    "en": "This could be done in a different way.",
                    "ua": "Można to zrobić inaczej."
                },
                {
                    "en": "The document can be downloaded online.",
                    "ua": "Dokument można pobrać online."
                }
            ]
        },
        {
            "label": "może / może",
            "color": "blue",
            "description": "<strong>Prawdopodobieństwo</strong> lub <strong>pozwolenie</strong>:",
            "examples": [
                {
                    "en": "The meeting may be postponed.",
                    "ua": "Spotkanie może zostać przełożone."
                },
                {
                    "en": "The flight might be cancelled.",
                    "ua": "Lot może zostać odwołany."
                },
                {
                    "en": "Photos may be taken here.",
                    "ua": "Tutaj możesz robić zdjęcia."
                }
            ]
        },
        {
            "label": "musi / musi - konieczność",
            "color": "amber",
            "description": "<strong>Konieczność</strong> lub <strong>obowiązek</strong>:",
            "examples": [
                {
                    "en": "This work must be done today.",
                    "ua": "Tę pracę należy wykonać dzisiaj."
                },
                {
                    "en": "The rules must be followed.",
                    "ua": "Należy przestrzegać zasad."
                },
                {
                    "en": "Taxes have to be paid on time.",
                    "ua": "Podatki trzeba płacić terminowo."
                }
            ]
        },
        {
            "label": "powinien/powinien",
            "color": "rose",
            "description": "<strong>Zalecenie</strong> lub <strong>porada</strong>:",
            "examples": [
                {
                    "en": "The report should be checked carefully.",
                    "ua": "Należy dokładnie sprawdzić raport."
                },
                {
                    "en": "Children should be protected.",
                    "ua": "Dzieci należy chronić."
                },
                {
                    "en": "This information ought to be verified.",
                    "ua": "Informacje te należy zweryfikować."
                }
            ]
        }
    ]
}

{
    "title": "3. Zastrzeżenia dotyczące czasowników modalnych",
    "sections": [
        {
            "label": "nie da się/nie da się tego zrobić",
            "color": "rose",
            "description": "<strong>Niemożliwość</strong>:",
            "examples": [
                {
                    "en": "This problem cannot be solved.",
                    "ua": "Tego problemu nie da się rozwiązać."
                },
                {
                    "en": "The deadline can't be extended.",
                    "ua": "Termin nie może zostać przedłużony."
                }
            ]
        },
        {
            "label": "nie wolno/nie wolno tego robić",
            "color": "amber",
            "description": "<strong>Zakaz</strong>:",
            "examples": [
                {
                    "en": "This information must not be shared.",
                    "ua": "Informacje te nie mogą być rozpowszechniane."
                },
                {
                    "en": "The password mustn't be revealed.",
                    "ua": "Hasła nie można ujawnić."
                }
            ]
        },
        {
            "label": "nie powinno/nie powinno być robione",
            "color": "sky",
            "description": "<strong>Niezalecane</strong>:",
            "examples": [
                {
                    "en": "This shouldn't be ignored.",
                    "ua": "Nie należy tego ignorować."
                },
                {
                    "en": "Children should not be left alone.",
                    "ua": "Dzieci nie należy zostawiać samych."
                }
            ]
        }
    ]
}

{
    "title": "4. Pytania z czasownikami modalnymi",
    "sections": [
        {
            "label": "Pytania yes/no",
            "color": "blue",
            "description": "<strong>Modalne + podmiot + Być + V3?</strong>:",
            "examples": [
                {
                    "en": "Can this be done today?",
                    "ua": "Czy da się to zrobić dzisiaj?"
                },
                {
                    "en": "Should the report be submitted now?",
                    "ua": "Czy musisz teraz złożyć raport?"
                },
                {
                    "en": "Must the rules be followed?",
                    "ua": "Czy musisz przestrzegać zasad?"
                }
            ]
        },
        {
            "label": "Jakie pytanie",
            "color": "emerald",
            "description": "<strong>Wh-word + modalne + podmiot + być + V3?</strong>:",
            "examples": [
                {
                    "en": "When can the work be finished?",
                    "ua": "Kiedy możesz zakończyć pracę?"
                },
                {
                    "en": "How should the problem be solved?",
                    "ua": "Jak należy rozwiązać problem?"
                },
                {
                    "en": "Where can the tickets be bought?",
                    "ua": "Gdzie mogę kupić bilety?"
                }
            ]
        }
    ]
}

{
    "title": "5. Porównanie trybu aktywnego i pasywnego z modami",
    "intro": "Jak zamienić zdanie czynne z czasownikiem modalnym w stronę bierną:",
    "rows": [
        {
            "en": "Active: You must finish this work.",
            "ua": "Musisz dokończyć tę pracę.",
            "note": "→ Passive: This work must be finished."
        },
        {
            "en": "Active: They can solve the problem.",
            "ua": "Mogą rozwiązać problem.",
            "note": "→ Passive: The problem can be solved."
        },
        {
            "en": "Active: You should check the report.",
            "ua": "Powinieneś sprawdzić raport.",
            "note": "→ Passive: The report should be checked."
        },
        {
            "en": "Active: We may postpone the meeting.",
            "ua": "Możemy przełożyć spotkanie.",
            "note": "→ Passive: The meeting may be postponed."
        }
    ],
    "warning": "📌 Czasownik modalny pozostaje niezmieniony, zmienia się jedynie czasownik główny!"
}

{
    "title": "6. Modale doskonałe w stronie biernej (o przeszłości)",
    "intro": "Formuła: <strong>modalne + zostały + V3</strong>:",
    "items": [
        {
            "label": "musiało być",
            "title": "musiało zostać zrobione",
            "subtitle": "Musiało zostać skradzione. - Musiało zostać skradzione."
        },
        {
            "label": "powinno być",
            "title": "powinno być zrobione",
            "subtitle": "Trzeba było to sprawdzić. - Trzeba było to sprawdzić."
        },
        {
            "label": "mogło być",
            "title": "można było to zrobić",
            "subtitle": "Można było tego uniknąć. - Można było tego uniknąć."
        },
        {
            "label": "mogło być",
            "title": "mogło zostać zrobione",
            "subtitle": "Mogło zostać utracone. - Może zgubili."
        }
    ]
}

{
    "title": "7. Modale doskonałe w stronie biernej: przykłady",
    "sections": [
        {
            "label": "Założenia dotyczące przeszłości",
            "color": "emerald",
            "description": "<strong>musi/może/może/mogło być + V3</strong>:",
            "examples": [
                {
                    "en": "The letter must have been sent yesterday.",
                    "ua": "List prawdopodobnie został wysłany wczoraj."
                },
                {
                    "en": "The window may have been broken by the kids.",
                    "ua": "Okno mogło zostać stłuczone przez dzieci."
                },
                {
                    "en": "The file might have been deleted accidentally.",
                    "ua": "Plik mógł zostać przypadkowo usunięty."
                }
            ]
        },
        {
            "label": "Krytyka przeszłych działań",
            "color": "rose",
            "description": "<strong>powinno być + V3</strong> (powinno być zrobione, ale nie zostało zrobione):",
            "examples": [
                {
                    "en": "The report should have been submitted on time.",
                    "ua": "Sprawozdanie należało złożyć w terminie."
                },
                {
                    "en": "The problem should have been fixed earlier.",
                    "ua": "Problem powinien zostać naprawiony wcześniej."
                },
                {
                    "en": "The warning should have been given.",
                    "ua": "Trzeba było dać ostrzeżenie."
                }
            ]
        },
        {
            "label": "Niezrealizowana szansa",
            "color": "blue",
            "description": "<strong>mogło być + V3</strong> (można było to zrobić):",
            "examples": [
                {
                    "en": "The accident could have been avoided.",
                    "ua": "Wypadku można było uniknąć."
                },
                {
                    "en": "The work could have been done faster.",
                    "ua": "Pracę można było wykonać szybciej."
                },
                {
                    "en": "The mistake could have been prevented.",
                    "ua": "Można było uniknąć błędów."
                }
            ]
        }
    ]
}

{
    "title": "8. Typowe błędy",
    "items": [
        {
            "label": "Błąd 1",
            "color": "rose",
            "title": "Pominięcie be po czasowniku modalnym.",
            "wrong": "The work must done today.",
            "right": "✅ The work must be done today."
        },
        {
            "label": "Błąd 2",
            "color": "amber",
            "title": "Używanie do po modalu.",
            "wrong": "It can to be fixed.",
            "right": "✅ It can be fixed."
        },
        {
            "label": "Błąd 3",
            "color": "sky",
            "title": "Niepoprawna forma w Perfect.",
            "wrong": "It should have be done.",
            "right": "✅ It should have been done."
        },
        {
            "label": "Błąd 4",
            "color": "rose",
            "title": "Zmiana czasownika modalnego.",
            "wrong": "The work musts be done.",
            "right": "✅ The work must be done."
        }
    ]
}
